        Node current = head;
        while (current != null) {
            System.out.print(current.data + " ");
            current = current.next;
        }
        System.out.println();
    }

    public static void main(String[] args) {
        insertAtTail(10);
        insertAtTail(20);
        insertAtTail(30);
        delete(20);
        printAll();
